<template>
	<view @touchmove.stop.prevent="stopRoll">
		<u-popup v-model="popupShow" :custom-style="customStyle" mode="bottom" :z-index="9999" safe-area-inset-bottom
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true" @close="close"
			@open="open">
			<view class="roll-box">
				<scroll-view scroll-y="true" class="scroll-Y" @scroll="handelScroll">
					<u-index-list :scrollTop="scrollTop" :index-list="indexList">
						<view v-for="(item, index) in indexList" :key="index">
							<template v-if="countryCodeList[item]">
								<u-index-anchor :index="item" />
								<view class="list-cell" v-for="item2,index2 in countryCodeList[item]" :key="index2"
									@click="handelItemClick(item2)">
									<view class="code">{{item2.c}}</view>
									<view class="city">{{item2.n}}</view>
								</view>
							</template>
						</view>
					</u-index-list>

				</scroll-view>
			</view>
		</u-popup>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			value: {
				type: Boolean,
				default: false,
			},
		},
		data() {
			return {
				scrollTop: 0,
				countryCodeList: {},
				indexList: [],
			};
		},
		computed: {
			customStyle() {
				const re = {}
				// #ifndef H5
				re.bottom = '110rpx'
				// #endif
				return re
			},
			popupShow: {
				get() {
					return this.value
				},
				set(val) {
					this.$emit('input', val)
				},
			},
		},
		watch: {

		},
		created() {

		},
		mounted() {

		},
		methods: {
			stopRoll() {},
			close() {

			},
			open() {
				this.$u.api.mobileCodeList().then(res => {
					const countryCodeList = {}
					this.indexList = [...new Set(...res.map(item => {
						if (Reflect.has(countryCodeList, item.i)) {
							countryCodeList[item.i].push(item)
						} else {
							countryCodeList[item.i] = [item]
						}
						return item.i
					}))]
					this.countryCodeList = countryCodeList
				})
			},
			handelScroll(e) {
				console.log('e.detail.scrollTop', e.detail.scrollTop)
				this.scrollTop = e.detail.scrollTop
			},
			handelItemClick(e) {
				this.$emit('change', e)
				this.popupShow = false
			},
		},
	};
</script>

<style scoped lang="scss" scoped>
	.scroll-Y {
		max-height: 1200rpx;

		.list-cell {
			display: flex;
			height: 70rpx;
			align-items: center;
			padding: 0 20rpx;
			gap: 10rpx;

			&+.list-cell {
				border-top: 1px solid #e5e5e5;
			}

			.code {
				min-width: 60rpx;
			}
		}
	}
</style>