<template>
	<u-popup v-model="popupShow" mode="center" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}"
		:border-radius="20" width="500rpx" :closeable="true" @open="open" @close="close">
		<view class="popup-content">
			<view class="title">
				{{title}}
			</view>
			<view class="qrcode">
		<!-- 		<uqrcode v-if="!qrcodeImage" @complete="uqrcodeComplete" ref="uqrcode" @longpress="saveqrcode"
					canvas-id="qrcode" sizeUnit="rpx" size="300" :value="qrcode"></uqrcode> -->
				<!-- <image style="width: 100%;height: 100%;" v-else :src="qrcode" mode="aspectFit"> -->
				<image style="width: 100%;height: 100%;"  :src="qrcode" mode="aspectFit">
				</image>
				<view v-show="isExpire" class="expire-mask">
					<view @click="reGetQrcode">重新获取</view>
				</view>
			</view>
			<view>
				<view>截图扫码</view>
			</view>
		</view>
	</u-popup>
</template>

<script>
	import {
		mapActions
	} from 'vuex'

	export default {
		components: {},
		props: {

		},
		data() {
			return {
				title: '',
				popupShow: false,
				qrcodeImage: '',

				ticket: '',
				qrcode: '', //二维码url
				isExpire: false,
				redirect: ''
			}
		},
		computed: {},
		watch: {},
		created() {},
		mounted() {},
		methods: {
			...mapActions([
				'getUserInfo'
			]),
			show({
				redirect
			}) {
				this.redirect = redirect
				this.title = '微信扫码'
				this.popupShow = true
			},
			open() {
				this.loadQrCode()
			},
			close() {
				this.stopCheck()
			},
			reGetQrcode() {
				this.loadQrCode()
			},
			// 获取二维码图片地址
			async loadQrCode() {
				this.isExpire = false
				const {
					ticket
				} = await this.$u.api.wxOfficialAccountTicket({
					return_url: this.redirect
				})
				this.ticket = ticket
				this.qrcode = `https://mp.weixin.qq.com/cgi-bin/showqrcode?ticket=${ticket}`
				this.checkStatus()
			},
			//二维码生成成功
			uqrcodeComplete(e) {
				this.$refs.uqrcode.toTempFilePath({
					success: res => {
						this.qrcodeImage = res.tempFilePath
					}
				});
			},
			checkStatus() {
				this.timer = setInterval(async () => {
					const {
						status,
						data
					} = await this.$u.api.wxOfficialTicketCheck({
						ticket: this.ticket
					})
					// ticket过期
					if (status == 1) {
						this.isExpire = true
						this.stopCheck()
					}
					// 直接三方登录
					else if (status == 2) {
						uni.setStorageSync('token', data.token)
						this.$u.vuex('token', data.token)
						this.$util.msg('登录成功')
						await this.getUserInfo()

						setTimeout(() => {
							if (this.redirect)
								this.$util.redirect(this.redirect)
							else
								this.$util.back()
						}, 1000)
					}
					// 授权成功，需要绑定或者注册新账号
					else if (status == 3) {
						this.stopCheck()
						this.$Router.replace({
							path: '/pages/user/thirdlogin',
							query: {
								login_token: data.login_token,
								redirect: this.redirect
							}
						})
					}
				}, 2000)
			},
			stopCheck() {
				if (this.timer) {
					clearInterval(this.timer)
					this.timer = null
				}
			},
			copyLink() {
				uni.setClipboardData({
					data: this.ticket,
					success() {
						uni.showToast({
							title: '复制成功',
							icon: 'success'
						});
					},
					fail() {
						uni.showToast({
							title: '复制失败',
							icon: 'none'
						});
					}
				});
			},
		}
	}
</script>


<style scoped lang="scss" scoped>
	.popup-content {
		display: flex;
		align-items: center;
		padding: 40rpx;
		flex-direction: column;
		gap: 20rpx;

		&>.title {
			font-weight: bolder;
			font-size: 30rpx;
		}

		.qrcode {
			width: 300rpx;
			height: 300rpx;
			cursor: pointer;
			position: relative;

			.expire-mask {
				position: absolute;
				top: 50%;
				left: 50%;
				display: flex;
				align-items: center;
				justify-content: center;
				width: 300rpx;
				height: 300rpx;
				color: #fff;
				text-align: center;
				background: rgba($color: #000000, $alpha: 0.5);
				transform: translate(-50%, -50%);
				user-select: none;
			}
		}
	}
</style>