<template>
	<u-modal ref="uModal" v-model="dialogFormVisible" :zoom="false" confirm-color="#FF504B" :title="title" :mask-close-able="false" show-cancel-button
		content="确认是否已经支付成功？" @confirm="checkStatus" @cancel="cancel" :async-close="true"></u-modal>
</template>

<script>
	export default {
		components: {},
		props: {},
		data() {
			return {
				title: '支付提示',
				dialogFormVisible: false,
				form: {
					order_sn: ''
				},
			}
		},
		computed: {},
		watch: {},
		created() {

		},
		mounted() {

		},
		methods: {
			show({
				order_sn
			}) {
				this.form.order_sn = order_sn
				this.dialogFormVisible = true
			},
			checkStatus() {
				this.$u.api.checkPayRegStatus({
					order_sn: this.form.order_sn
				}).then(res => {
					this.$refs.uModal.clearLoading()
					const {
						status,
						userinfo,
					} = res
					if (status == 1) {
						const {
							token,
							uid
						} = userinfo
						this.$emit('success', {
							token,
							uid
						})
						this.close()
					} else {						
						this.$util.msg('检测到订单未支付成功！')
					}
				})
			},
			cancel(){
				this.$emit('cancel')
			},
			close() {
				this.form = this.$options.data().form
				this.dialogFormVisible = false
			},
		},
	}
</script>

