<template>
	<view>
		<u-popup v-model="dialogFormVisible" mode="center" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}"
			:border-radius="20" width="600rpx" :closeable="true" @close="close">
			<view class="popup-content">
				<scroll-view scroll-y="true" style="height: 300rpx;" v-if="payList.pay_reg_tip">
					<u-parse :html="payList.pay_reg_tip"></u-parse>
				</scroll-view>
				<u-form label-width="140">
					<!-- <u-form-item label="金额">
						<text style="color: red; font-weight: bold;">{{payList.pay_reg_money}}</text>
					</u-form-item> -->
					<u-form-item>
						<view class="pay-list">
							<view class="pay-item" :class="{on:idx == selectedPayIndex}"
								v-for="pay,idx in payList.pay_list" :key="idx" @click="handelChangePayWay(pay,idx)">
								<u-image :src="$util.img(pay.img)" width="30rpx" height="30rpx" border-radius="50%" />
								<text>{{pay.title}}</text>
							</view>
						</view>
					</u-form-item>
					<u-button @click="doPay" type="warning">立即支付 <text>￥{{payList.pay_reg_money}}</text></u-button>
				</u-form>
			</view>
		</u-popup>
		<qrcode-popup :qrcodeshow.sync="qrcodeshow" :title="qrcodeTitle" :qrcodeurl="qrcodeUrl"
			@close="handelQrcodePopupClose" :copymark="copyMark" />
		<confirm-dialog ref="confirm-dialog" @success="handelConfirm" @cancel="handelQrcodePopupClose" />
	</view>
</template>

<script>
	import {
		deepClone,
		handleHtmlImg
	} from '@/common/fun.js'
	import QrcodePopup from './qrcode-popup'
	import ConfirmDialog from './confirm-dialog'

	export default {
		name: "reg-pay",
		components: {
			'qrcode-popup': QrcodePopup,
			'confirm-dialog': ConfirmDialog,
		},
		data() {
			return {
				dialogFormVisible: false,
				payList: {
					pay_reg_money: '',
					pay_reg_tip: '',
					pay_list: [],
				}, //支付方式列表
				// 替换图标
				iconList: [{
						icon: 'icon-yue1',
						name: 'balance'
					},
					{
						icon: 'icon-weixinzhifu1',
						name: 'wechat'
					},
					{
						icon: 'icon-zhifubaozhifu4',
						name: 'alipay'
					},
					{
						icon: 'icon-zhifubaozhifu4',
						name: 'alipayuser'
					},
					{
						icon: 'icon-QQ',
						name: 'qqpay'
					},
				],

				selectedPayIndex: -1,

				qrcodeshow: false,
				qrcodeUrl: '',
				copyMark: '',
				paystatusTimer: null,

				// 下单表单
				form: {
					pay_type: '',
					pay_event: 'payreg',
					pay_data: {
						reg_code: ''
					},
					pay_id: '',
				},
			};
		},
		computed: {
			qrcodeTitle() {
				const pay_way = this.payList.pay_list[this.selectedPayIndex]
				return pay_way ? pay_way.title : ''
			},
			curPayName() {
				const pay_way = this.payList.pay_list[this.selectedPayIndex]
				return pay_way ? pay_way.name : ''
			},
		},
		methods: {
			show({
				reg_code
			}) {
				this.form.pay_data.reg_code = reg_code
				this.dialogFormVisible = true
				this.fetchData()
			},
			// 加载支付列表
			async fetchData() {
				const {
					pay_reg_money,
					pay_reg_tip,
					pay_list
				} = await this.$u.api.getPayRegConfig()
				this.payList.pay_reg_money = pay_reg_money
				this.payList.pay_reg_tip = handleHtmlImg(pay_reg_tip)
				this.payList.pay_list = pay_list
				this.payList.pay_list = pay_list.map(item => {
					let icon = this.iconList.find(item2 => item2.name == item.name)
					item.icon = icon.icon
					return item
				})
				if (pay_list.length) {
					this.handelChangePayWay(this.payList.pay_list[0], 0)
				}
			},
			handelChangePayWay(row, idx) {
				if (idx == this.selectedPayIndex)
					return
				this.form.pay_type = row.name
				this.form.pay_id = row.id
				this.selectedPayIndex = idx
			},
			doPay() {
				// this.$u.throttle(this.buy, 1000)
				this.buy()
			},
			async buy() {
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
				const copy = deepClone(this.form)
				copy.pay_data = JSON.stringify(copy.pay_data)
				const {
					expire_time,
					order_sn,
					url,
					url_type
				} = await this.$u.api.pay(copy)
				uni.hideLoading()

				if (this.paystatusTimer) {
					clearInterval(this.paystatusTimer)
				}
				this.paystatusTimer = setInterval(() => {
					this.paystatus(order_sn)
				}, 2000)

				let that = this

				switch (url_type) {
					case 1:
						// 扫码支付
						this.qrcodeUrl = url

						//收款人身份
						if (this.curPayName == 'alipayuser' && copy.pay_data && copy.pay_data.true_name) {
							this.copyMark = copy.pay_data.true_name;
						} else {
							this.copyMark = '';
						}
						if (this.curPayName == 'alipay' || this.curPayName == 'alipayuser') {
							this.$util.openAppUrl(this.qrcodeUrl)
						}
						this.qrcodeshow = true
						break;
					case 2:
						// 跳转网页
						//#ifdef MP-WEIXIN
						if (this.curPayName == 'alipay') {
							this.qrcodeUrl = url
							this.qrcodeshow = true
						}
						//#endif
						//#ifdef H5
						// window.location.href = url

						setTimeout(() => window.open(url, '_blank'))
						this.$refs['confirm-dialog'].show({
							order_sn
						})
						//#endif
						break;
					case 3:
						//#ifdef H5
						window.location.href = res.url
						//#endif
						break;
					case 4:
						//#ifdef H5
						jWeixin.config({
							debug: false, // 开启调试模式,调用的所有api的返回值会在客户端alert出来，若要查看传入的参数，可以在pc端打开，参数信息会通过log打出，仅在pc端时才会打印。
							appId: pay_data.appId, // 必填，公众号的唯一标识
							timestamp: pay_data.timeStamp, // 必填，生成签名的时间戳
							nonceStr: pay_data.nonceStr, // 必填，生成签名的随机串
							signature: pay_data.paySign, // 必填，签名
							jsApiList: [ //这里是需要用到的接口名称  
								'checkJsApi', //判断当前客户端版本是否支持指定JS接口  
								'onMenuShareAppMessage', //分享接口  
								'getLocation', //获取位置  
								'openLocation', //打开位置  
								'scanQRCode', //扫一扫接口  
								'chooseWXPay', //微信支付  
								'chooseImage', //拍照或从手机相册中选图接口  
								'previewImage', //预览图片接口  
								'uploadImage' //上传图片  
							], // 必填，需要使用的JS接口列表
							openId: this.userinfo.wxgzh_openid
						})
						//付款
						jWeixin.chooseWXPay({
							appId: pay_data.appId,
							timestamp: pay_data
								.timeStamp, // 支付签名时间戳，注意微信jssdk中的所有使用timestamp字段均为小写。但最新版的支付后台生成签名使用的timeStamp字段名需大写其中的S字符
							nonceStr: pay_data.nonceStr, // 支付签名随机串，不长于 32
							package: pay_data
								.package, // 统一支付接口返回的prepay_id参数值，提交格式如：prepay_id=\*\*\*）
							signType: pay_data.signType, // 签名方式，默认为'SHA1'，使用新版支付需传入'MD5'
							paySign: pay_data.paySign, // 支付签名
							success: function(res) {
								// 余额支付直接跳到订单详情
								// that.ordersn = ''
								// that.order_id = ''
								// if (that.paystatusTimer) {
								// 	clearInterval(that.paystatusTimer)
								// }
								// that.$util.msg('支付成功');
								// setTimeout(() => {
								// 	that.$util.on('/pages/order/info?id=' + that.order_id);
								// }, 1000)

							},
							cancel: function(res) {
								that.$util.msg('取消支付');
								if (that.paystatusTimer) {
									clearInterval(that.paystatusTimer)
								}
							},
							fail: function(res) {
								that.$util.msg('付款失败');
								if (that.paystatusTimer) {
									clearInterval(that.paystatusTimer)
								}

							}
						});
						//#endif
						break;
					case 5:
						// #ifdef MP
						let mp_pay_name = ''
						if (uni.requestOrderPayment) {
							mp_pay_name = 'requestOrderPayment'
						} else {
							mp_pay_name = 'requestPayment'
						}
						uni.showLoading({
							title: `支付中`
						})
						uni[mp_pay_name]({
							timeStamp: pay_data.timeStamp,
							nonceStr: pay_data.nonceStr,
							package: pay_data.package,
							signType: pay_data.signType,
							paySign: pay_data.paySign,
							success: function(res) {
								uni.hideLoading()
								that.$util.msg(res.msg)
							},
							fail: function(e) {
								uni.hideLoading();
								that.$util.msg('取消支付')
							},
							complete: function(e) {
								uni.hideLoading();
								if (e.errMsg == 'requestPayment:cancel' || e.errMsg ==
									'requestOrderPayment:cancel') return
								that.$util.msg('取消支付');
							},
						});
						// #endif
						break;
					case 6:
						// #ifdef APP-PLUS
						// console.log(res)
						uni.showLoading({
							mask: true,
							title: '支付中...'
						});
						uni.requestPayment({
							provider: 'wxpay',
							orderInfo: pay_data,
							success: (e) => {
								that.$util.msg(`支付成功`)
							},
							fail: (e) => {
								that.$util.msg(`支付失败`)
							},
							complete: () => {
								// 余额支付直接跳到订单详情
								// that.ordersn = ''
								// that.order_id = ''
								if (that.paystatusTimer) {
									clearInterval(that.paystatusTimer)
								}
								uni.hideLoading()
							},
						});
						// #endif
						break;
					case 7:
						// #ifdef APP-PLUS
						uni.showLoading({
							mask: true,
							title: '支付中...'
						});
						uni.requestPayment({
							provider: 'alipay',
							orderInfo: pay_data,
							success: (e) => {
								that.$util.msg(`支付成功`)
							},
							fail: (e) => {
								console.log(e)
								that.$util.msg(`支付失败`)
							},
							complete: (e) => {
								console.log(e)
								// 余额支付直接跳到订单详情
								// that.ordersn = ''
								// that.order_id = ''
								if (that.paystatusTimer) {
									clearInterval(that.paystatusTimer)
								}
								uni.hideLoading()
							},
						});
						// #endif
						break;
					default:
						break;
				}
			},
			async paystatus(order_sn) {
				try {
					const {
						status,
						userinfo,
					} = await this.$u.api.checkPayRegStatus({
						order_sn
					})
					if (status == 1) {
						const {
							token,
							uid
						} = userinfo
						this.$util.msg('支付成功')
						clearInterval(this.paystatusTimer)
						this.$emit('success', {
							token,
							uid
						})
						this.close()
					}
				} catch (e) {
					clearInterval(this.paystatusTimer)
				}
			},
			// 弹框支付二维码关闭回调
			handelQrcodePopupClose() {
				if (this.paystatusTimer) {
					clearInterval(this.paystatusTimer)
				}
			},
			// 网页跳转支付成功回调
			handelConfirm(e) {
				this.$emit('success', e)
			},
			close() {
				this.form = this.$options.data().form
				this.url = ''
				this.dialogFormVisible = false
				if (this.paystatusTimer) {
					clearInterval(this.paystatusTimer)
					this.paystatusTimer = null
				}
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.popup-content {
		padding: 40rpx;
	}

	.iconfont {
		color: #09bb07;
		font-size: 29rpx;
		margin-right: 4px;
	}

	.iconfont.icon-zhifubaozhifu4 {
		color: #00aaea;
		font-size: 29rpx;
	}

	.iconfont.icon-QQ {
		color: #3b8cfe;
		font-size: 29rpx;
	}

	.pay-list {
		display: flex;
		gap: 20rpx;
		flex-wrap: wrap;

		.pay-item {
			border: 1px solid #d4d4d4;
			cursor: pointer;
			height: 52rpx;
			line-height: 1.5;
			// line-height: 52rpx;
			position: relative;
			// width: 160rpx;
			display: flex;
			justify-content: center;
			align-items: center;
			border-radius: 12rpx;
			padding: 0 16rpx;
			gap: 10rpx;
		}

		.on {
			border: 2rpx solid #5440e9;
		}
	}
</style>