<!-- 蓝色简洁登录页面 -->
<template>
	<view class="page" :style="[regPageStyle]">
		<slideCode v-if="slideCode[0].show" :session_id="session_id[0]" @close="slideCode[0].show = false"
			@success="$slideCode_success(0, $event)"></slideCode>
		<slideCode v-if="slideCode[1].show" :session_id="session_id[1]" @close="slideCode[1].show = false"
			@success="$slideCode_success(1, $event)"></slideCode>
		<regPay ref="regpay" @success="handelPaySuccess" />

		<OpenWind :type="openWinType" />

		<!-- <image class="logo" @click="$util.on('/pages/index/index')" :src="icoimg" mode="aspectFit"></image> -->
		<view style="display: flex;justify-content: center;padding-top:20rpx;">

			<u-image :src="$util.img(sysconfig.logo)" width="360rpx" height="160rpx" mode="aspectFit"
				@click="$util.on('/pages/index/index')" />
		</view>
		<view class="title">
			账号注册
		</view>

		<view class="form">


			<view class="form-item">
				<view class="input">
					<u-input v-model="username" placeholder="请输入登录用户名" height="40" />
				</view>
			</view>
			<view class="form-item">
				<view class="input">
					<u-input v-model="pwd" type="password" placeholder="请输入登录密码" height="40" />
				</view>
			</view>
			<view class="form-item" v-if="openRegTwoPassword">
				<view class="input">
					<u-input v-model="pwd1" type="password" placeholder="请确认密码" height="40" />
				</view>
			</view>
			<view class="form-item" v-if="openPayPassword">
				<view class="input">
					<u-input v-model="trade_password" type="number" placeholder="请输入交易密码" height="40" :maxlength="6" />
				</view>
			</view>
			<template v-if="openRegInputMobile">
				<view class="form-item">
					<template v-if="mobileCodeOpen">
						<view class="input-group">
							<view class="mobile-code" @click="showMobileCode=true">+{{mobile_code}}</view>
							<u-input v-model="mobile" placeholder="请输入手机号" :height="40" />
						</view>
					</template>
					<template v-else>
						<u-input v-model="mobile" placeholder="请输入手机号" :height="40" />
					</template>
				</view>
				<view class="form-item">
					<view class="input" style="width:360rpx">
						<u-input v-model="captcha" type="text" maxlength="6" placeholder="请输入验证码" height="40" />
					</view>
					<view class="" :style="is_sendCode?'color:#c3c8d9;':'color:red;'" @click="sendCode(10)">

						<u-verification-code :seconds="seconds" ref="uCode" @start="codeStart" @end="codeEnd"
							@change="codeChange" start-text="获取验证码" change-text="X秒"></u-verification-code>
						<view class="">
							{{tips}}
						</view>
					</view>
				</view>
			</template>
			<!-- <view class="form-item">
					<view class="input">
						<u-input v-model="qq" type="text" placeholder="请输入联系QQ" height="40" />
					</view>
				</view> -->


			<view class="form-item" v-if="openRegInputPid">
				<view class="input">
					<u-input v-model="pid" type="number" placeholder="上级编号(可不填)" height="40" />
				</view>
			</view>


			<view class="login-button" @click="reg">
				立即注册
			</view>
			<need-know type="reg" />
		</view>

		<third-list ref="third-list" />
		<mobile-code-choose v-model="showMobileCode" @change="handelCountryCodeChange" />
		<agree-popup v-model="agreePopup" @refuse="handelRefuse" @agree="handelAgree" />
	</view>
</template>
<script>
	import slideCode from '@/components/slideCode.vue'
	import regPay from '@/components/reg-pay'
	import OpenWind from '@/components/OpenWind'
	import MobileCodeChoose from '@/components/mobile-code-choose'
	import NeedKnow from './components/login/NeedKnow'
	import Third from './components/login/Third'
	import AgreePopup from './components/login/AgreePopup'

	import {
		mapGetters,
		mapActions,
		mapMutations
	} from 'vuex'

	export default {
		components: {
			slideCode,
			regPay,
			OpenWind,
			'mobile-code-choose': MobileCodeChoose,
			'need-know': NeedKnow,
			'third-list': Third,
			'agree-popup': AgreePopup,
		},
		data() {
			return {
				username: '', //账号
				pwd: '', //密码
				session_id: [], //会自动生成的
				pid: '', //上级ID
				pwd1: '',
				trade_password: '', //交易密码
				qq: '',
				slideCode: [{
					show: false
				}, {
					show: false
				}],
				logo: '',
				icoimg: '',
				thirdLoginList: [

				],

				mobile: '', //注册手机号码
				captcha: '', //验证码

				tips: '',
				seconds: 60,
				is_sendCode: false, //是否发送验证码

				openRegInputPid: false, // 开启上级用户
				openPayReg: false, // 开启付费注册
				openRegTwoPassword: false, //开启用户注册需要二次输入登录密码
				openRegInputMobile: false, // 注册强制填写手机号
				openPayPassword: false, //注册交易密码

				redirect: '', //登录成功返回地址
				openWinType: 'user_reg_open_window', //弹框类型

				customStyle: {
					position: 'absolute',
					opacity: 0,
					width: '64rpx',
					height: '64rpx',
					top: '0',
					left: '0',
					padding: '0',
				},

				showMobileCode: false,
				mobile_code: '86',
			};
		},
		computed: {
			...mapGetters({
				h5RegBgOpen: 'loginConfig/h5RegBgOpen',
				h5RegBgImg: 'loginConfig/h5RegBgImg',
				mobileCodeOpen: 'loginConfig/mobileCodeOpen',
				showAgreePopup: 'loginConfig/showAgreePopup',
				agreeUser: 'loginConfig/agreeUser',
				isThirdLogin: 'loginConfig/isThirdLogin',
			}),
			regPageStyle() {
				const re = {}
				if (this.h5RegBgOpen) {
					re.backgroundImage = `url(${this.$util.img2(this.h5RegBgImg)})`
					re.backgroundSize = '100% 100%'
					re.backgroundRepeat = 'no-repeat'
				}
				return re
			},
			agreePopup: {
				get() {
					return this.showAgreePopup
				},
				set(v) {
					this.setShowAgreePopup(v)
				}
			}
		},
		provide() {
			return {
				getRegPayIns: () => this.$refs['regpay'],
				getRedirect: () => this.redirect
			}
		},
		onLoad(e) {
			if (uni.getStorageSync('token')) {
				this.$util.redirect('/pages/index/index')
			} else {
				if (e.redirect == '_store') {
					this.redirect = uni.getStorageSync('callback_url')
				} else {
					this.redirect = this.$Route.query.redirect
				}

				//获取缓存pid
				this.getThirdLogin();
				this.$slideCode_init(0); //初始化图形滑块
				this.$slideCode_init(1); //初始化图形滑块
				if (!this.pid) {
					this.pid = uni.getStorageSync('pid');
				}
			}
		},
		methods: {
			...mapActions({
				loadLoginConf: 'loginConfig/loadLoginConf'
			}),
			...mapMutations({
				setShowAgreePopup: 'loginConfig/setShowAgreePopup',
				setIsThirdLogin: 'loginConfig/setIsThirdLogin',
				setAgreeUser: 'loginConfig/setAgreeUser'
			}),
			codeChange(text) {
				this.tips = text;
			},
			//发送验证码
			sendCode() {

				if (!this.$u.test.mobile(this.mobile)) return this.$u.toast('请输入正确的手机号')

				this.slideCode[1].show = true; //滑块验证码


			},
			codeStart() {
				this.is_sendCode = true;
			},
			codeEnd() {
				this.is_sendCode = false;
			},
			canGetCode() {
				if (this.$refs.uCode.canGetCode) {
					// 模拟向后端请求验证码
					uni.showLoading({
						title: '正在获取验证码'
					})


					let data = {
						send_type: 11,
						mobile: this.mobile,
						mobile_code: this.mobile_code,
						session: this.session_id[1],
					}
					this.$u.api.sendCode(data).then(res => {
						uni.hideLoading();
						// 这里此提示会被this.start()方法中的提示覆盖
						this.$u.toast('验证码已发送');
						// 通知验证码组件内部开始倒计时
						this.$refs.uCode.start();
					}).catch((res) => {
						console.log(res);
						this.$u.toast('验证码已发送');
					})

				} else {
					this.$u.toast('倒计时结束后再发送');
				}
			},
			//进入协议
			parse() {
				this.$util.on('/pages/common/parse');
			},
			//获取登录配置
			async getThirdLogin() {
				const res = await this.loadLoginConf()

				this.thirdLoginList = res.thirdLoginList
				this.logo = res.logo
				this.icoimg = res.icoimg
				this.openRegInputPid = res.open_reg_input_pid
				this.openPayReg = res.open_pay_reg
				this.openRegTwoPassword = res.open_reg_two_password
				this.openRegInputMobile = res.open_reg_input_mobile
				this.openPayPassword = res.open_pay_password

				uni.setStorageSync('open_reg_input_mobile', res.open_reg_input_mobile)
			},

			$getRandomNunber(start, end) {
				return Math.floor(Math.random() * (end - start) + start)
			},
			$slideCode_init(index) {
				this.session_id[index] = this.$getRandomNunber(0, 999999999); //唯一id
				this.slideCode[index].yanzheng = false; //图形验证码是否验证通过
				this.slideCode[index].x = 0 //图形验证码的水平偏移值
			},
			$slideCode_success(index, data) {
				this.slideCode[index].yanzheng = true //验证通过
				this.slideCode[index].x = data.x //偏移值
				if (index == 1) {
					this.canGetCode() //获取验证码
				} else {
					this.yzm(index)
				}

			},


			//当前登录按钮操作
			reg() {
				if (!this.agreeUser) {
					this.setShowAgreePopup(true)
					this.setIsThirdLogin(false)
					return;
				}
				if (this.openRegInputMobile) {
					if (!this.mobile) {
						this.$util.msg('请输入手机号码');
						return;
					}
					if (!this.captcha) {
						this.$util.msg('请输入验证码');
						return;
					}
				} else {
					var that = this;

					if (!that.username) {
						this.$util.msg('请输入登录用户名');
						return;
					}
					if (!that.pwd) {
						this.$util.msg('请输入登录密码');
						return;
					}
					if (this.openRegTwoPassword && that.pwd != this.pwd1) {
						this.$util.msg('两次密码不一致');
						return
					}

					if (this.openPayPassword && !this.trade_password) {
						this.$util.msg('请输入交易密码');
						return;
					}

				}
				this.slideCode[0].show = true
			},
			async yzm(index) {
				if (this.slideCode[index].yanzheng === true) { //图形滑块是否验证通过

					uni.showLoading({
						mask: true,
						title: '加载中...'
					})

					const {
						reg_status,
						reg_data,
						// userinfo,
						token,
					} = await this.$u.api.reg({
						username: this.username,
						password: this.pwd,
						password2: this.pwd1,
						trade_password: this.trade_password,
						qq: this.qq,
						pid: this.pid,
						session: this.session_id[index],
						mobile: this.mobile,
						mobile_code: this.mobile_code,
						captcha: this.captcha,
					})
					uni.hideLoading()
					if (reg_status == 1) {
						this.$refs['regpay'].show({
							reg_code: reg_data.reg_code
						})
					} else {
						//存储token
						uni.setStorageSync('token', token)
						this.$u.vuex('token', token)

						this.$util.msg('注册成功')
						await this.getUserInfo()
						setTimeout(() => {
							//注册成功前往首页
							this.$util.redirect('/pages/index/index');
						}, 1500)
					}
					// this.loading = false;

					// uni.showToast({
					// 	title: '验证通过咯',
					// 	icon: 'none',
					// 	duration: 2000
					// });

				} else {
					this.slideCode[index].show = true
				}
			},
			getUserInfo() {
				return new Promise((resolve, reject) => {
					this.$u.api.userinfo().then(res => {
						let userinfo = res.userinfo
						userinfo.isLogin = true
						userinfo.token = uni.getStorageSync('token')
						for (let key in userinfo) {
							this.$u.vuex('userinfo.' + key, userinfo[key]);
						}
						resolve()
					}).catch(e => {
						reject(e)
					})
				})
			},
			// 付费注册成功回调
			async handelPaySuccess({
				token
			}) {
				//存储token
				uni.setStorageSync('token', token)
				this.$util.msg('注册成功')
				await this.getUserInfo()
				setTimeout(() => {
					//注册成功前往首页
					this.$util.redirect('/pages/index/index');
				}, 1500)
			},
			// 国家码改变事件
			handelCountryCodeChange(e) {
				this.mobile_code = e.c
			},
			handelRefuse() {
				this.setShowAgreePopup(false)
			},
			handelAgree() {
				this.setShowAgreePopup(false)
				this.setAgreeUser(true)
				if (!this.isThirdLogin) {
					this.reg()
				} else {
					this.$refs['third-list'].doThirdLogin()
				}
			},
		}
	};
</script>
<style scoped>
