		width: 100%;
		display: flex;
		align-items: center;
		background-color: #F0F3F7;
		border-radius: 20px;

		.mobile-code {
			// margin-left: 40rpx;
			margin-right: 40rpx;
			position: relative;
			color: rgb(192, 196, 204);

			&::after {
				content: '';
				position: absolute;
				width: 2rpx;
				height: 30rpx;
				background-color: rgb(192, 196, 204);
				right: -20rpx;
				top: 50%;
				transform: translateY(-50%);
			}
		}

		::v-deep {
			.u-input {
				padding-left: 0 !important;
			}
		}
	}

	.page {
		overflow-y: auto;

		.title {
			width: 100%;
			padding-left: 86rpx;
			color: #1e2331;
			font-weight: 600;
			font-size: 44rpx;
			margin-top: 16rpx;
		}

		.logo {
			margin-top: 104rpx;
			margin-left: 86rpx;
			width: 70rpx;
			height: 70rpx;

		}

		.form {

			width: 100%;
			margin-top: 20rpx;
			display: flex;
			align-items: center;
			justify-content: flex-start;
			flex-direction: column;

			.form-item {
				padding: 20rpx 40rpx;
				display: flex;
				align-items: center;
				justify-content: space-between;
				margin-top: 52rpx;
				width: 620rpx;

				background: #F0F3F7;
				border-radius: 40rpx;

				.input {
					width: 560rpx;
				}

				.img {
					width: 30rpx;
