					align-items: center;
					justify-content: center;
				}

				.active {

					border: none;
					color: #fff;
				}

				.link {
					color: #ff594d;
				}
			}

			.rigest {
				width: 100%;
				font-weight: 400;
				color: #9b9fa8;
