				display: flex;
				align-items: center;
				justify-content: center;

				.register {
					color: #ff594d;
				}
			}
		}


		.third-box {

			width: 100%;
			margin-top: 60rpx;
			margin-bottom: 20rpx;
			display: flex;
			align-items: center;
			justify-content: flex-start;
